{
  "articles": [
    {
      "unit_type": "article",
      "headline": "I prezzi dei prodotti o all'ingrosso e al",
      "text": "La pubblicazione di un bollettino La determinazione dei costi nelle produzione e nelle province in",
      "page_span": [1]
